import instructor
from instructor.retry import backoff

class ContextBloatError(Exception):
    pass

@backoff(max_retries=3)
def safe_structured_call(client, messages, response_model):
    try:
        return client.chat.completions.create(
            messages=messages,
            response_model=response_model,
            temperature=0
        )
    except instructor.retry.RetryError as e:
        if 'Structured output validation retries exhausted' in str(e):
            raise ContextBloatError('Context window likely exceeded causing validation failures')
        raise

