from instructor import Instructor

class ConversationSummarizer:
    def __init__(self, client):
        self.client = Instructor(client)

    def summarize_history(self, messages, max_history_messages=5):
        if len(messages) <= max_history_messages:
            return messages

        # Extract conversation for summarization
        history = messages[1:max_history_messages]  # Skip system
        summary_prompt = [
            {'role': 'system', 'content': 'Summarize this conversation in 2-3 sentences preserving key decisions and context:'},
            *history
        ]

        class Summary(BaseModel):
            summary: str

        summary = self.client.chat.completions.create(
            messages=summary_prompt,
            response_model=Summary
        )

        return [messages[0], {'role': 'system', 'content': f"Conversation summary: {summary.summary}"}] + messages[-2:]

summarizer = ConversationSummarizer(client)
messages = summarizer.summarize_history(messages)
